import{_ as t,o as a,c as r,ag as i}from"./chunks/framework.BPmc_f4o.js";const o="/wordpress-application-layer-auth-rate-limit-tab.webp",s="/wordpress-application-layer-applications-1-tab.webp",n="/wordpress-application-layer-applications-2-tab.webp",l="/wordpress-application-layer-ip-filters-tab.webp",d="/wordpress-application-layer-collections-tab.webp",c="/wordpress-application-layer-properties-tab.webp",p="/wordpress-application-layer-routes-tab.webp",u="/wordpress-application-layer-webhook-tab.webp",v=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"WordPress Application Layer","text":"WordPress as a modern application backend.","tagline":"Decide what data is exposed, who can access it, and how it is shaped. Self-hosted, open-source, built for developers who are done rebuilding the same things from scratch.","image":{"src":"/wordpress-application-layer-applications-1-tab.webp","alt":"WordPress Application Layer admin interface"},"actions":[{"theme":"brand","text":"Get Started","link":"/presentation"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/AfterglowWeb/wordpress-rest-api-firewall"}]},"features":[{"icon":"🔐","title":"Authentication & Rate Limiting","details":"Authenticate clients with WordPress Application Password (hardened to a single authorised user) or JWT. OAuth requires Pro. Set per-user request quotas with configurable time windows. Auto-blacklist IPs that exceed thresholds — no third-party service required.","link":"/users/users","linkText":"Learn more"},{"icon":"🗂️","title":"Properties & Models","details":"Apply sitewide response transforms for free — resolve embedded terms, authors & attachments, flatten rendered fields, strip domain from URLs. Pro adds per-property disable, rename and remap, plus fully custom JSON schemas.","link":"/models/models","linkText":"Learn more"},{"icon":"🔍","title":"Routes & Exposure Control","details":"Browse every REST API route and its schema from the admin. Globally disable HTTP methods, post types, or taxonomies from the API. Pro adds per-route policy — disable or redirect individual routes, restrict them to specific users, and apply fine-grained rate limits per endpoint.","link":"/routes/routes","linkText":"Learn more"},{"icon":"🛡️","title":"WordPress Security Hardening","details":"Disable XML-RPC, comments, pingbacks, RSS feeds, and the theme editor. Secure file permissions, protect the uploads directory, and enforce HTTP security headers — all in one place.","link":"/global-security","linkText":"Learn more"},{"icon":"📦","title":"Multi-Application Isolation","details":"Serve a corporate website, a mobile app, and an e-commerce store from one WordPress installation — each with its own authentication context, data view, rate limit, and webhook configuration.","link":"/applications/applications","linkText":"Learn more (Pro)"},{"icon":"⚡","title":"Event-Driven Automations","details":"Chain actions on WordPress lifecycle events — send emails, trigger webhooks, fire custom hooks — with optional conditions. No code required, no external automation service needed.","link":"/automations/automations","linkText":"Learn more (Pro)"}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),h={name:"index.md"};function m(g,e,f,y,b,w){return a(),r("div",null,[...e[0]||(e[0]=[i('<div class="vp-doc home-extra"><h2 id="own-your-stack-own-your-data" tabindex="-1">Own your stack. Own your data. <a class="header-anchor" href="#own-your-stack-own-your-data" aria-label="Permalink to &quot;Own your stack. Own your data.&quot;">​</a></h2><p>SaaS CMSes are convenient until they are not — pricing changes, data lives on someone else&#39;s server, and migrating out is painful. WordPress has powered the open web for 20 years. <strong>Application Layer gives it the application infrastructure it was always missing.</strong></p><p>Authentication, data shaping, API scoping, event automation, security hardening: the features you have been assembling from a dozen plugins on every project, now in one coherent layer — with a clean admin UI, a full hooks API, and zero vendor lock-in.</p><hr><h2 id="built-for-real-development-workflows" tabindex="-1">Built for real development workflows <a class="header-anchor" href="#built-for-real-development-workflows" aria-label="Permalink to &quot;Built for real development workflows&quot;">​</a></h2><div class="pillars-grid"><div class="pillar-card"><h3 id="control-what-you-expose" tabindex="-1">Control what you expose <a class="header-anchor" href="#control-what-you-expose" aria-label="Permalink to &quot;Control what you expose&quot;">​</a></h3><p>WordPress exposes a lot by default — user data, internal meta, raw field structures. Application Layer lets you audit every route, globally disable HTTP methods, post types or taxonomies, and in Pro, decide field by field what leaves your server.</p></div><div class="pillar-card"><h3 id="shape-data-for-your-front-end" tabindex="-1">Shape data for your front-end <a class="header-anchor" href="#shape-data-for-your-front-end" aria-label="Permalink to &quot;Shape data for your front-end&quot;">​</a></h3><p>Stop massaging responses client-side. Apply sitewide transforms for free: resolve embedded terms, flatten rendered wrappers, strip domain from URLs. Pro adds per-property rename, remap, and fully custom schemas.</p></div><div class="pillar-card"><h3 id="isolate-clients-from-each-other" tabindex="-1">Isolate clients from each other <a class="header-anchor" href="#isolate-clients-from-each-other" aria-label="Permalink to &quot;Isolate clients from each other&quot;">​</a></h3><p>One WordPress installation. Multiple applications — each with its own auth method, data view, rate limit, and secret. The same content, safely served to different consumers.</p></div><div class="pillar-card"><h3 id="self-host-with-confidence" tabindex="-1">Self-host with confidence <a class="header-anchor" href="#self-host-with-confidence" aria-label="Permalink to &quot;Self-host with confidence&quot;">​</a></h3><p>No subscription required for the core feature set. No telemetry. No external dependency. Your WordPress, your server, your rules.</p></div></div><hr><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><div class="use-cases-grid"><div class="use-case-card"><h3 id="headless-cms" tabindex="-1">Headless CMS <a class="header-anchor" href="#headless-cms" aria-label="Permalink to &quot;Headless CMS&quot;">​</a></h3><p>Use WordPress as the content back-end for a React, Next.js, Nuxt, or mobile app. Enforce authentication, transform responses to match your front-end schema, and keep WordPress internals invisible to consumers.</p></div><div class="use-case-card"><h3 id="replace-your-saas-cms" tabindex="-1">Replace your SaaS CMS <a class="header-anchor" href="#replace-your-saas-cms" aria-label="Permalink to &quot;Replace your SaaS CMS&quot;">​</a></h3><p>Self-host your content infrastructure. Keep editorial teams on a familiar interface while giving developers a clean, controlled API — without recurring costs or third-party data custody.</p></div><div class="use-case-card"><h3 id="multi-tenant-applications" tabindex="-1">Multi-Tenant Applications <a class="header-anchor" href="#multi-tenant-applications" aria-label="Permalink to &quot;Multi-Tenant Applications&quot;">​</a></h3><p>Serve multiple client applications from a single WordPress back-end. Isolate authentication, content views, and rate limits per application — each client sees only what they are entitled to.</p></div><div class="use-case-card"><h3 id="multilingual-distribution" tabindex="-1">Multilingual Distribution <a class="header-anchor" href="#multilingual-distribution" aria-label="Permalink to &quot;Multilingual Distribution&quot;">​</a></h3><p>Serve content in multiple languages across separate websites or applications, each with its own REST API scope, response schema, and delivery configuration.</p></div></div><hr><h2 id="free-vs-pro" tabindex="-1">Free vs Pro <a class="header-anchor" href="#free-vs-pro" aria-label="Permalink to &quot;Free vs Pro&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th style="text-align:center;">Free</th><th style="text-align:center;">Pro</th></tr></thead><tbody><tr><td>REST API route explorer</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Authentication &amp; Rate Limiting</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Properties &amp; Models (sitewide transforms)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Routes: global method / post-type / taxonomy disable</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>WordPress Security Hardening</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Webhook (single, post lifecycle events)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Hooks &amp; Filters API</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Multiple Applications</td><td style="text-align:center;">—</td><td style="text-align:center;">✅</td></tr><tr><td>IP Filtering (blacklist)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>IP Filtering whitelist + CIDR + country blocking</td><td style="text-align:center;">—</td><td style="text-align:center;">✅</td></tr><tr><td>Collections &amp; Sort Order</td><td style="text-align:center;">—</td><td style="text-align:center;">✅</td></tr><tr><td>Properties &amp; Models (per-property control + custom schemas)</td><td style="text-align:center;">—</td><td style="text-align:center;">✅</td></tr><tr><td>Settings Route schema editor (ACF options, menus)</td><td style="text-align:center;">—</td><td style="text-align:center;">✅</td></tr><tr><td>Per-Route Policy (per-route disable, redirect, user restriction)</td><td style="text-align:center;">—</td><td style="text-align:center;">✅</td></tr><tr><td>Automations</td><td style="text-align:center;">—</td><td style="text-align:center;">✅</td></tr><tr><td>Multiple Webhooks (unlimited, per application)</td><td style="text-align:center;">—</td><td style="text-align:center;">✅</td></tr><tr><td>Email Templates</td><td style="text-align:center;">—</td><td style="text-align:center;">✅</td></tr><tr><td>Request Logs &amp; Audit Trail</td><td style="text-align:center;">—</td><td style="text-align:center;">✅</td></tr></tbody></table><hr><h2 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h2><p>The next modules in development:</p><div class="roadmap-grid"><div class="roadmap-card"><span class="roadmap-tag">Coming next</span><p><strong>WooCommerce Bridge</strong></p><p>Headless access to WooCommerce — products, cart, checkout, and Stripe/PayPal payments — through the same application security layer.</p></div><div class="roadmap-card"><span class="roadmap-tag">Coming next</span><p><strong>Forms Bridge</strong></p><p>Secure form submission endpoints with entry management, configurable data retention, GDPR options, and AES-256 encryption. Compatible with WPForms and Contact Form 7.</p></div><div class="roadmap-card"><span class="roadmap-tag">Planned</span><p><strong>Site Import / Export</strong></p><p>Cherry-pick content and configuration to sync, migrate, or replicate between WordPress installations through the REST API — powered by the same field mapping already in Models.</p></div><div class="roadmap-card"><span class="roadmap-tag">Planned</span><p><strong>Editorial Workflow</strong></p><p>Authors scoped to their own posts and media. Validation workflows, co-authoring, post duplication, post type conversion, and multi-author taxonomies — for production editorial teams.</p></div><div class="roadmap-card"><span class="roadmap-tag">Planned</span><p><strong>Static Pages &amp; Custom URLs</strong></p><p>Spin up static landing pages on any domain directly from WordPress. Choose any URL pattern for posts and pages — free from WordPress&#39;s default URL constraints.</p></div><div class="roadmap-card"><span class="roadmap-tag">Planned</span><p><strong>Database Encryption</strong></p><p>An optional encryption layer for sensitive data stored in <code>wp_options</code> and custom tables — transparent to the application.</p></div></div><hr><h2 id="screenshots" tabindex="-1">Screenshots <a class="header-anchor" href="#screenshots" aria-label="Permalink to &quot;Screenshots&quot;">​</a></h2><div class="screenshots-grid"><figure><img src="'+o+'" alt="Auth and Rate Limiting tab"><figcaption>Auth &amp; Rate Limiting</figcaption></figure><figure><img src="'+s+'" alt="Applications list"><figcaption>Applications List</figcaption></figure><figure><img src="'+n+'" alt="Create Application"><figcaption>New Application</figcaption></figure><figure><img src="'+l+'" alt="IP Filters"><figcaption>IP Filtering</figcaption></figure><figure><img src="'+d+'" alt="Collections"><figcaption>Collections</figcaption></figure><figure><img src="'+c+'" alt="Properties"><figcaption>Properties &amp; Models</figcaption></figure><figure><img src="'+p+'" alt="Routes"><figcaption>Routes Policy</figcaption></figure><figure><img src="'+u+'" alt="Webhooks"><figcaption>Webhooks</figcaption></figure></div></div>',1)])])}const P=t(h,[["render",m]]);export{v as __pageData,P as default};
